// ============================================================
// LAW 1 — T ORDER
// ============================================================
const T_ORDER = {};
for (let i = 0; i < 26; i++) T_ORDER[String.fromCharCode(65 + i)] = i + 1;
function encodeWord(w) { return w.toUpperCase().split("").filter(c => T_ORDER[c]).map(c => T_ORDER[c]); }
function wordValue(w) { return encodeWord(w).reduce((a, b) => a + b, 0); }

